import React, { useState } from "react";
import { useDispatch } from "react-redux";
import { submitInteraction, fetchInteractions } from "../store/interactionSlice";

export default function InteractionForm() {
  const dispatch = useDispatch();
  const [form, setForm] = useState({
    hcp_name: "",
    rep_name: "",
    interaction_type: "visit",
    raw_input: "",
  });
  const [submitting, setSubmitting] = useState(false);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!form.hcp_name || !form.raw_input) return;
    setSubmitting(true);
    await dispatch(submitInteraction(form));
    await dispatch(fetchInteractions());
    setForm({ hcp_name: "", rep_name: "", interaction_type: "visit", raw_input: "" });
    setSubmitting(false);
  };

  return (
    <form className="card" onSubmit={handleSubmit}>
      <div className="form-group">
        <label>HCP Name</label>
        <input name="hcp_name" value={form.hcp_name} onChange={handleChange} placeholder="Dr. Priya Iyer" />
      </div>
      <div className="form-group">
        <label>Rep Name</label>
        <input name="rep_name" value={form.rep_name} onChange={handleChange} placeholder="Your name" />
      </div>
      <div className="form-group">
        <label>Interaction Type</label>
        <select name="interaction_type" value={form.interaction_type} onChange={handleChange}>
          <option value="visit">Visit</option>
          <option value="call">Call</option>
          <option value="email">Email</option>
        </select>
      </div>
      <div className="form-group">
        <label>Notes</label>
        <textarea
          name="raw_input"
          value={form.raw_input}
          onChange={handleChange}
          placeholder="Discussed CardioPlus samples, doctor was receptive, wants follow-up literature next month."
        />
      </div>
      <button className="btn-primary" type="submit" disabled={submitting}>
        {submitting ? "Logging..." : "Log Interaction"}
      </button>
    </form>
  );
}
